export function parseArgs(argv) {
  const result = { _: [] }
  let index = 0
  const len = argv.length
  while (index < len) {
    const arg = argv[index]
    if (!arg.startsWith('-')) {
      result._.push(arg)
      index += 1
    } else if (arg.startsWith('--')) {
      const key = arg.slice(2)
      const value = argv[index + 1]
      const next = argv[index + 2]
      if (value !== undefined && !value.startsWith('-')) {
        result[key] = value
        index += 2
      } else if (value !== undefined && value.startsWith('-') && key.includes('=')) {
        const [keyVal, val] = key.split('=', 2)
        result[keyVal] = val
        index += 1
      } else if (next !== undefined && !(next.startsWith('-') && next.startsWith('--'))) {
        if (arg.includes('=')) {
          const [keyVal, val] = key.split('=', 2)
          result[keyVal] = val
        } else {
          result[key] = true
        }
        index += 1
      } else if (arg.includes('=')) {
        const [keyVal, val] = arg.split('=', 2)
        result[keyVal] = val
        index += 1
      } else {
        result[key] = true
        index += 1
      }
    } else {
      result[arg] = true
      index += 1
    }
  }
  return result
}

